export async function searchTestCandidates(
	validExperimentTypes: ReadonlyArray< ExperimentType >,
	newAiSettings?: AiSettings
): Promise< void > {
	const state = select( NAB_DATA ).getPageAttribute(
		'ai/testGenerationState'
	);
	if ( ! state || 'intro' !== state.type ) {
		return;
	}

	try {
		if ( newAiSettings ) {
			const previousAiSettings =
				select( NAB_DATA ).getPluginSetting( 'aiSettings' );
			if ( previousAiSettings?.type === 'ready' ) {
				throw new Error( 'cant-override-settings' );
			}
			await breathe( () => saveAiSettings( newAiSettings, state.id ) );
		}
	} catch ( error ) {
		await setState( {
			id: state.id,
			type: 'error',
			reason: getErrorCode( error ),
		} );
		return;
	}

	const currentAiSettings =
		select( NAB_DATA ).getPluginSetting( 'aiSettings' );
	if ( currentAiSettings?.type !== 'ready' ) {
		throw new Error( 'invalid-ai-settings' );
	}

	const abTesting = await breathe( () => getAbTestingData( state.id ) );
	if ( 'error' === abTesting.type ) {
		await setState( {
			id: state.id,
			type: 'error',
			reason: getErrorCode( abTesting.error ),
		} );
		return;
	}

	try {
		const result = await getCachedCandidates(
			abTesting.aiAnalysis,
			abTesting.base.experiments,
			state.id
		);
		if ( result ) {
			const candidates = await expandFirstCandidate( {
				candidates: result.candidates,
				experiments: abTesting.base.experiments,
				siteAnalysis: result.siteAnalysis,
				stateId: state.id,
				validExperimentTypes,
			} );
			await setState( {
				id: state.id,
				type: 'hypothesis-selection',
				siteAnalysis: result.siteAnalysis,
				candidates,
				testing: abTesting.base,
			} );
			return;
		}
	} catch ( _ ) {}

	try {
		const siteAnalysis = await analyzeSite(
			abTesting.aiAnalysis,
			state.id
		);
		const baseCandidates = await processSiteAnalysis(
			siteAnalysis,
			abTesting.base.experiments,
			state.id
		);
		const candidates = await expandFirstCandidate( {
			candidates: baseCandidates,
			experiments: abTesting.base.experiments,
			siteAnalysis,
			stateId: state.id,
			validExperimentTypes,
		} );
		await setState( {
			id: state.id,
			type: 'hypothesis-selection',
			siteAnalysis,
			candidates,
			testing: abTesting.base,
		} );
	} catch ( error ) {
		await setState( {
			id: state.id,
			type: 'error',
			reason: getErrorCode( error ),
		} );
	}
}

export async function generateTestHypotheses(
	candidate: AiTestCandidate,
	validExperimentTypes: ReadonlyArray< ExperimentType >
): Promise< void > {
	const aiSettings = select( NAB_DATA ).getPluginSetting( 'aiSettings' );
	if ( aiSettings?.type !== 'ready' ) {
		return;
	}

	const state = select( NAB_DATA ).getPageAttribute(
		'ai/testGenerationState'
	);
	if ( ! state || 'hypothesis-selection' !== state.type ) {
		return;
	}

	if ( 'ready' === candidate.hypothesisState.status ) {
		await updateCandidate( {
			...candidate,
			hypothesisState: {
				...candidate.hypothesisState,
				isVisible: true,
			},
		} );
		return;
	}

	if ( 'pending' !== candidate.hypothesisState.status ) {
		return;
	}

	candidate = await updateCandidate( {
		...candidate,
		hypothesisState: { status: 'generating' },
	} );

	await loadTestHypotheses( {
		candidate,
		experiments: state.testing.experiments,
		language: state.siteAnalysis.metaInformation.language,
		validExperimentTypes,
	} );
}

export async function createTestFromHypothesis(
	hypothesis: AiTestHypothesis,
	validExperimentTypes: ReadonlyArray< ExperimentType >
): Promise< void > {
	const aiSettings = select( NAB_DATA ).getPluginSetting( 'aiSettings' );
	if ( aiSettings?.type !== 'ready' ) {
		return;
	}

	const state = select( NAB_DATA ).getPageAttribute(
		'ai/testGenerationState'
	);
	if ( ! state || 'hypothesis-selection' !== state.type ) {
		return;
	}

	await setState( { ...state, type: 'creating-test' } );
	try {
		const type = validExperimentTypes.find(
			( t ) => t.name === hypothesis.testType
		);
		if ( ! type ) {
			throw new Error( 'invalid-experiment-type' );
		}

		const baseExperiment = await createExperiment( type );

		const defaultGoal: Maybe< Goal > = type.supports.automaticGoalSetup
			? {
					id: uuid(),
					attributes: {
						name: _x( 'Default Goal', 'text', 'nelio-ab-testing' ),
					},
					conversionActions:
						type.supports.automaticGoalSetup(
							baseExperiment.alternatives[ 0 ]
						) ?? [],
			  }
			: undefined;

		const scope: Maybe< ReadonlyArray< ScopeRule > > =
			type.supports.scope === 'urls' ||
			type.supports.scope === 'urls-or-php'
				? [
						{
							id: uuid(),
							attributes: {
								type: 'exact',
								value: hypothesis.controlUrl,
							},
						},
				  ]
				: undefined;

		const experiment = await saveExperiment( {
			...baseExperiment,
			scope: scope ?? baseExperiment.scope,
			name: hypothesis.name,
			description: hypothesis.description,
			ai: {
				version: 1,
				basedOnNelioAIHypothesis: hypothesis.id,
			},
			alternatives: [
				{
					id: 'control' as const,
					attributes: {
						postId: hypothesis.control.id,
						postType: hypothesis.control.type,
					},
					links: createAlternative().links,
				},
				...hypothesis.variants.map( ( v ): Alternative => {
					const alt = createAlternative();
					return {
						...alt,
						attributes: {
							...alt.attributes,
							name: v.name,
						},
						ai: {
							isReady: false,
							name: v.name,
							changes: v.changes,
						},
					};
				} ),
			],
			goals: [
				defaultGoal,
				...hypothesis.goals.map(
					( g ): Goal => ( {
						id: uuid(),
						attributes: {
							name: g.name,
						},
						ai: {
							name: g.name,
							description: g.description,
						},
						conversionActions: [],
					} )
				),
			].filter( isDefined ),
		} );

		await setState( { ...state, experiment, type: 'done' } );
	} catch ( error ) {
		await setState( {
			id: state.id,
			type: 'error',
			reason: getErrorCode( error ),
		} );
	}
}

